use std::io;

fn main()
{
    let stdin = io::stdin();
    let mut buffer = String::new();
    stdin.read_line(&mut buffer).unwrap();
    buffer = buffer.trim().to_string();
    let mut n = buffer.parse::<u32>().unwrap();
    let mut cnt = 0;
    while n > 0 {
        n >>= 1;
        cnt += 1;
    }

    println!("{}", cnt);
}

